const { SQSClient, DeleteMessageCommand, ChangeMessageVisibilityCommand } = require('@aws-sdk/client-sqs');
const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, UpdateCommand, PutCommand } = require('@aws-sdk/lib-dynamodb');
const https = require('https');
const crypto = require('crypto');

const sqsClient = new SQSClient({ region: process.env.AWS_REGION });
const dynamoClient = new DynamoDBClient({ region: process.env.AWS_REGION });
const docClient = DynamoDBDocumentClient.from(dynamoClient);

const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY;
const MAX_AMOUNT = 100000;
const TIMEOUT_MS = 25000;

const makeHttpsRequest = (url, options, data) => {
  return new Promise((resolve, reject) => {
    const timeout = setTimeout(() => {
      req.destroy();
      reject(new Error('Request timeout'));
    }, TIMEOUT_MS);

    const req = https.request(url, options, (res) => {
      let body = '';
      let chunks = 0;
      const maxChunks = 1000;

      res.on('data', (chunk) => {
        chunks++;
        if (chunks > maxChunks) {
          req.destroy();
          clearTimeout(timeout);
          reject(new Error('Response too large'));
          return;
        }
        body += chunk;
        if (body.length > 1048576) {
          req.destroy();
          clearTimeout(timeout);
          reject(new Error('Response body too large'));
        }
      });

      res.on('end', () => {
        clearTimeout(timeout);
        resolve({ statusCode: res.statusCode, body });
      });
    });

    req.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });

    if (data) {
      req.write(data);
    }
    req.end();
  });
};

const validateOrder = (order) => {
  if (!order || typeof order !== 'object') {
    throw new Error('Invalid order object');
  }

  if (!order.orderId || typeof order.orderId !== 'string' || order.orderId.length > 100) {
    throw new Error('Invalid orderId');
  }

  if (!order.customerId || typeof order.customerId !== 'string' || order.customerId.length > 100) {
    throw new Error('Invalid customerId');
  }

  if (typeof order.amount !== 'number' || order.amount <= 0 || order.amount > MAX_AMOUNT) {
    throw new Error('Invalid amount');
  }

  if (!order.currency || typeof order.currency !== 'string' || !/^[A-Z]{3}$/.test(order.currency)) {
    throw new Error('Invalid currency');
  }

  if (order.paymentMethod && typeof order.paymentMethod !== 'string') {
    throw new Error('Invalid paymentMethod');
  }

  return true;
};

const sanitizeForLog = (obj) => {
  const sanitized = JSON.parse(JSON.stringify(obj));
  const sensitiveFields = ['cardNumber', 'cvv', 'password', 'apiKey', 'token', 'secret'];
  
  const redact = (o) => {
    for (const key in o) {
      if (sensitiveFields.some(field => key.toLowerCase().includes(field.toLowerCase()))) {
        o[key] = '[REDACTED]';
      } else if (typeof o[key] === 'object' && o[key] !== null) {
        redact(o[key]);
      }
    }
  };
  
  redact(sanitized);
  return sanitized;
};

const callPaymentAPI = async (order) => {
  const idempotencyKey = crypto.createHash('sha256')
    .update(`${order.orderId}-${order.customerId}-${order.amount}`)
    .digest('hex');

  const paymentData = JSON.stringify({
    orderId: order.orderId,
    customerId: order.customerId,
    amount: order.amount,
    currency: order.currency,
    paymentMethod: order.paymentMethod || 'card',
    idempotencyKey: idempotencyKey
  });

  const options = {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(paymentData),
      'X-API-Key': PAYMENT_API_KEY,
      'X-Idempotency-Key': idempotencyKey
    },
    timeout: TIMEOUT_MS
  };

  try {
    const response = await makeHttpsRequest(PAYMENT_API_URL, options, paymentData);
    
    if (response.statusCode === 200 || response.statusCode === 201) {
      const result = JSON.parse(response.body);
      return {
        success: true,
        transactionId: result.transactionId,
        status: result.status
      };
    } else {
      return {
        success: false,
        error: `Payment API returned status ${response.statusCode}`,
        statusCode: response.statusCode
      };
    }
  } catch (error) {
    return {
      success: false,
      error: error.message
    };
  }
};

const updateDynamoDB = async (order, paymentResult) => {
  const timestamp = new Date().toISOString();
  
  const params = {
    TableName: ORDERS_TABLE,
    Key: {
      orderId: order.orderId
    },
    UpdateExpression: 'SET #status = :status, #updatedAt = :updatedAt, #paymentResult = :paymentResult',
    ExpressionAttributeNames: {
      '#status': 'status',
      '#updatedAt': 'updatedAt',
      '#paymentResult': 'paymentResult'
    },
    ExpressionAttributeValues: {
      ':status': paymentResult.success ? 'COMPLETED' : 'FAILED',
      ':updatedAt': timestamp,
      ':paymentResult': paymentResult
    },
    ConditionExpression: 'attribute_exists(orderId)'
  };

  try {
    await docClient.send(new UpdateCommand(params));
    return { success: true };
  } catch (error) {
    if (error.name === 'ConditionalCheckFailedException') {
      const putParams = {
        TableName: ORDERS_TABLE,
        Item: {
          orderId: order.orderId,
          customerId: order.customerId,
          amount: order.amount,
          currency: order.currency,
          status: paymentResult.success ? 'COMPLETED' : 'FAILED',
          createdAt: timestamp,
          updatedAt: timestamp,
          paymentResult: paymentResult
        }
      };
      await docClient.send(new PutCommand(putParams));
      return { success: true };
    }
    throw error;
  }
};

const processOrder = async (message) => {
  let order;
  
  try {
    order = JSON.parse(message.body);
  } catch (error) {
    console.error('Failed to parse message body:', error.message);
    return { success: false, error: 'Invalid JSON' };
  }

  try {
    validateOrder(order);
  } catch (error) {
    console.error('Order validation failed:', error.message, sanitizeForLog(order));
    return { success: false, error: error.message };
  }

  console.log('Processing order:', sanitizeForLog(order));

  const paymentResult = await callPaymentAPI(order);
  
  if (!paymentResult.success) {
    console.error('Payment failed for order:', order.orderId, paymentResult.error);
  } else {
    console.log('Payment successful for order:', order.orderId, paymentResult.transactionId);
  }

  try {
    await updateDynamoDB(order, paymentResult);
    console.log('DynamoDB updated for order:', order.orderId);
  } catch (error) {
    console.error('Failed to update DynamoDB for order:', order.orderId, error.message);
    return { success: false, error: 'DynamoDB update failed' };
  }

  return { success: true };
};

exports.handler = async (event) => {
  console.log('Received event with', event.Records.length, 'records');

  const results = {
    processed: 0,
    failed: 0,
    errors: []
  };

  for (const record of event.Records) {
    try {
      const result = await processOrder(record);
      
      if (result.success) {
        results.processed++;
        
        try {
          await sqsClient.send(new DeleteMessageCommand({
            QueueUrl: record.eventSourceARN.replace('arn:aws:sqs:', 'https://sqs.').replace(':queue/', '.amazonaws.com/'),
            ReceiptHandle: record.receiptHandle
          }));
        } catch (deleteError) {
          console.error('Failed to delete message:', deleteError.message);
        }
      } else {
        results.failed++;
        results.errors.push({
          messageId: record.messageId,
          error: result.error
        });
        console.error('Failed to process order:', result.error);
      }
    } catch (error) {
      results.failed++;
      results.errors.push({
        messageId: record.messageId,
        error: error.message
      });
      console.error('Unexpected error processing record:', error.message);
    }
  }

  console.log('Processing complete:', results);

  return {
    statusCode: 200,
    body: JSON.stringify(results)
  };
};